import React, { useEffect, useState } from "react";

const TicketHistory = ({ employee }) => {
  const [ticketData, setTicketData] = useState([]);
  const [fromDate, setFromDate] = useState("");
  const [toDate, setToDate] = useState("");

  useEffect(() => {
    if (employee?.empId || employee?.empld) {
      fetchData();
    }
  }, [employee]);

  const fetchData = async () => {
    try {
      const empId = employee.empId || employee.empld;

      const response = await fetch(
        `https://prasa-app-yde3.onrender.com/ticket-expenses?empId=${encodeURIComponent(
          empId
        )}`
      );

      const data = await response.json();
      setTicketData(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error(error);
      setTicketData([]);
    }
  };

  const filteredData = ticketData.filter((item) => {
    const d = new Date(item.ticket_date);
    const from = fromDate ? new Date(fromDate) : null;
    const to = toDate ? new Date(toDate) : null;

    if (from && d < from) return false;
    if (to && d > to) return false;
    return true;
  });

  const downloadReport = () => {
    alert("Ticket Monthly Report download coming soon 🔥");
  };

  return (
    <div style={pageWrapper}>
      <div style={card}>
        {/* Header */}
        <div style={cardHeader}>
          <button
            style={backButton}
            onClick={() => window.history.back()}
          >
            ←
          </button>
          <h2 style={titleText}>Ticket Expense History</h2>
        </div>

        <p style={employeeText}>
          Employee: {employee.empName || employee.name} •{" "}
          {employee.empId || employee.empld}
        </p>

        {/* Filters */}
        <div style={filterRow}>
          <div style={filterField}>
            <label style={filterLabel}>From Date</label>
            <input
              type="date"
              value={fromDate}
              onChange={(e) => setFromDate(e.target.value)}
              style={filterInput}
            />
          </div>

          <div style={filterField}>
            <label style={filterLabel}>To Date</label>
            <input
              type="date"
              value={toDate}
              onChange={(e) => setToDate(e.target.value)}
              style={filterInput}
            />
          </div>

          <button style={resetButton} onClick={fetchData}>
            Reset
          </button>
        </div>

        {/* Table */}
        <div style={tableWrapper}>
          <table style={table}>
            <thead>
              <tr>
                <th>Date</th>
                <th>Purpose</th>
                <th>Assigned To</th>
                <th>Amount</th>
              </tr>
            </thead>
            <tbody>
              {filteredData.length > 0 ? (
                filteredData.map((item) => (
                  <tr key={item.id}>
                    <td>{item.ticket_date}</td>
                    <td>{item.purpose}</td>
                    <td>{item.assigned_to}</td>
                    <td>₹ {item.amount}</td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="4" style={noDataText}>
                    No records found
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* Download bottom-left */}
        <div style={downloadRow}>
          <button style={downloadButton} onClick={downloadReport}>
            📄 Download Monthly Report
          </button>
        </div>
      </div>
    </div>
  );
};

export default TicketHistory;

/* ---------- STYLES (same as Travel) ---------- */

const green = "#0F9D58";

const pageWrapper = {
  minHeight: "100vh",
  background: "#EAF8F0",
  padding: "20px",
};

const card = {
  background: "#ffffff",
  borderRadius: "16px",
  padding: "20px 24px",
  boxShadow: "0 4px 20px rgba(0,0,0,0.06)",
};

const cardHeader = {
  display: "flex",
  alignItems: "center",
  gap: "10px",
};

const backButton = {
  border: "none",
  background: "#ffffff",
  borderRadius: "999px",
  width: "36px",
  height: "36px",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  fontSize: "20px",
  color: green,
  boxShadow: "0 2px 6px rgba(0,0,0,0.15)",
  cursor: "pointer",
};

const titleText = {
  margin: 0,
  fontSize: "22px",
  fontWeight: 600,
  color: green,
};

const employeeText = {
  marginTop: "6px",
  marginBottom: "14px",
  color: "#555",
  fontSize: "14px",
};

const filterRow = {
  display: "flex",
  gap: "16px",
  alignItems: "flex-end",
  background: "#F3FBF6",
  padding: "12px 14px",
  borderRadius: "12px",
  marginBottom: "16px",
};

const filterField = {
  display: "flex",
  flexDirection: "column",
  flex: 1,
};

const filterLabel = {
  fontSize: "13px",
  color: "#444",
  marginBottom: "4px",
};

const filterInput = {
  padding: "8px 10px",
  borderRadius: "8px",
  border: "1px solid #ccc",
  fontSize: "14px",
};

const resetButton = {
  background: green,
  color: "#fff",
  border: "none",
  borderRadius: "10px",
  padding: "9px 16px",
  cursor: "pointer",
  fontSize: "14px",
};

const tableWrapper = {
  marginTop: "10px",
  overflowX: "auto",
};

const table = {
  width: "100%",
  borderCollapse: "collapse",
};

const noDataText = {
  textAlign: "center",
  padding: "18px 0",
  color: "#777",
};

const downloadRow = {
  marginTop: "16px",
  textAlign: "left",
};

const downloadButton = {
  background: green,
  color: "#fff",
  border: "none",
  borderRadius: "10px",
  padding: "10px 18px",
  fontSize: "15px",
  fontWeight: 600,
  cursor: "pointer",
